Verify that console output maintains agent compatibility by testing stream separation, plain text output, and proper environment detection.

## Background
AI coding agents are primary users of sqlmodel_rust. Tests must verify:
1. Agents can parse stdout (semantic data only)
2. Decorative output goes to stderr only
3. Plain mode has no ANSI escape codes
4. Agent detection works correctly

## Implementation Details

### Test File Location
crates/sqlmodel-console/tests/agent_compat.rs

### Stream Separation Tests
#[test]
fn test_query_results_go_to_stdout() {
    // Capture stdout/stderr
    let (stdout, stderr) = capture_output(|| {
        let console = SqlModelConsole::new();
        let results = sample_query_results();
        console.print_query_results(&results);
    });

    // Results should be in stdout
    assert!(stdout.contains("row1"));
    // Decorations should be in stderr or empty
    assert!(!stdout.contains("\x1b[")); // no ANSI in stdout
}

#[test]
fn test_errors_go_to_stderr() {
    let (stdout, stderr) = capture_output(|| {
        let console = SqlModelConsole::new();
        console.print_error(&sample_error());
    });

    // Stdout should be clean
    assert!(stdout.is_empty() || !stdout.contains("Error"));
    // Error details in stderr
    assert!(stderr.contains("Error") || stderr.contains("error"));
}

### Plain Mode Tests
#[test]
fn test_plain_mode_no_ansi() {
    let console = SqlModelConsole::plain();
    let output = console.render_to_string(&sample_table());

    // No ANSI escape codes
    assert!(!output.contains("\x1b["));
    assert!(!output.contains("\033["));
    // But content is there
    assert!(output.contains("column1"));
}

#[test]
fn test_plain_mode_parseable_format() {
    let console = SqlModelConsole::plain();

    // Test error output is parseable
    let error_output = console.format_error(&sample_error());
    // Should follow pattern: ERROR: <message>
    assert!(error_output.starts_with("ERROR:") || 
            error_output.contains("[ERROR]"));

    // Test progress is parseable
    let progress = OperationProgress::new("test", 100).completed(50);
    let progress_output = progress.render_plain();
    // Should contain percentage in parseable form
    assert!(progress_output.contains("50%") || 
            progress_output.contains("50/100"));
}

